import datetime
import email.message
import json as jsonlib
import typing
import urllib.request
from collections.abc import Mapping
from http.cookiejar import Cookie, CookieJar

# Minimal utility functions used by Headers
def normalize_header_key(key: typing.Union[bytes, str], lower: bool = False, encoding: typing.Optional[str] = None) -> bytes:
    """
    Normalize a header key to bytes. Optionally lower-case it.
    """
    if isinstance(key, bytes):
        result = key
    else:
        enc = encoding or "ascii"
        result = key.encode(enc, errors="surrogateescape")
    if lower:
        return result.lower()
    return result

def normalize_header_value(value: typing.Union[bytes, str], encoding: typing.Optional[str] = None) -> bytes:
    """
    Normalize a header value to bytes.
    """
    if isinstance(value, bytes):
        return value
    enc = encoding or "ascii"
    return str(value).encode(enc, errors="surrogateescape")

def obfuscate_sensitive_headers(headers: "Headers") -> "Headers":
    """
    Return a shallow copy of headers with sensitive values obfuscated for display.
    """
    copy_headers = headers.copy()
    for key in list(copy_headers.keys()):
        k_lower = key.lower()
        if k_lower in {"authorization", "proxy-authorization"}:
            copy_headers[key] = "*****"
    return copy_headers


class Headers(typing.MutableMapping[str, str]):
    """
    HTTP headers, represented as a case-insensitive multi-dict.
    """

    def __init__(
        self,
        headers: typing.Optional[typing.Union["Headers", Mapping[str, str], typing.Iterable[typing.Tuple[str, str]]]] = None,
        encoding: typing.Optional[str] = None,
    ) -> None:
        """
        Initialize headers.

        headers may be:
        - None: empty headers
        - Headers: copy of another Headers instance
        - Mapping: mapping of str -> str
        - Iterable of (key, value) pairs.
        """
        if headers is None:
            self._list = []  # type: typing.List[typing.Tuple[bytes, bytes, bytes]]
        elif isinstance(headers, Headers):
            self._list = list(headers._list)
        elif isinstance(headers, Mapping):
            self._list = [
                (
                    normalize_header_key(k, lower=False, encoding=encoding),
                    normalize_header_key(k, lower=True, encoding=encoding),
                    normalize_header_value(v, encoding),
                )
                for k, v in headers.items()
            ]
        else:
            self._list = [
                (
                    normalize_header_key(k, lower=False, encoding=encoding),
                    normalize_header_key(k, lower=True, encoding=encoding),
                    normalize_header_value(v, encoding),
                )
                for k, v in headers
            ]

        self._encoding = encoding

    @property
    def encoding(self) -> str:
        """
        Determine and return the encoding used for header keys/values.

        The method will attempt common encodings and fall back to iso-8859-1.
        """
        if self._encoding is None:
            for encoding in ["ascii", "utf-8"]:
                for key, value in self.raw:
                    try:
                        key.decode(encoding)
                        value.decode(encoding)
                    except UnicodeDecodeError:
                        break
                else:
                    # All values fit the encoding.
                    self._encoding = encoding
                    break
            else:
                self._encoding = "iso-8859-1"
        return self._encoding

    @encoding.setter
    def encoding(self, value: str) -> None:
        """
        Set the header encoding explicitly.
        """
        self._encoding = value

    @property
    def raw(self) -> typing.List[typing.Tuple[bytes, bytes]]:
        """
        Returns a list of the raw header items, as (key, value) byte pairs.
        """
        return [(raw_key, value) for raw_key, _, value in self._list]

    def keys(self) -> typing.KeysView[str]:
        """
        Return a view of header field-names (decoded to strings).
        """
        return {key.decode(self.encoding): None for _, key, value in self._list}.keys()

    def values(self) -> typing.ValuesView[str]:
        """
        Return a view of header values (decoded to strings). When multiple
        values exist for the same key, the last one will be represented.
        """
        values_dict: typing.Dict[str, str] = {}
        for _, key, value in self._list:
            str_key = key.decode(self.encoding)
            str_value = value.decode(self.encoding)
            values_dict[str_key] = str_value
        return values_dict.values()

    def get_all(self, name: str) -> typing.List[str]:
        """
        Get all values for the header 'name', preserving order.
        """
        n = name.encode(self.encoding)
        return [v.decode(self.encoding) for _, key, v in self._list if key == n.lower() or key == n]

    def __getitem__(self, name: str) -> str:
        """
        Get the most recent value for header 'name'.
        """
        n = name.encode(self.encoding).lower()
        for raw_key, key, value in reversed(self._list):
            if key == n:
                return value.decode(self.encoding)
        raise KeyError(name)

    def __setitem__(self, name: str, value: str) -> None:
        """
        Set header 'name' to a single 'value', replacing any existing values.
        """
        # Remove existing keys
        n_raw = normalize_header_key(name, lower=False, encoding=self._encoding)
        n_lower = normalize_header_key(name, lower=True, encoding=self._encoding)
        self._list = [(rk, k, v) for rk, k, v in self._list if k != n_lower]
        self._list.append((n_raw, n_lower, normalize_header_value(value, self._encoding)))

    def update(self, headers: typing.Union["Headers", Mapping[str, str], typing.Iterable[typing.Tuple[str, str]]]) -> None:
        """
        Update headers with another mapping or iterable of (name, value) pairs.
        Existing values for a header name are removed and replaced by the new one.
        """
        if isinstance(headers, Headers):
            for raw_key, key, value in headers._list:
                self._list.append((raw_key, key, value))
        elif isinstance(headers, Mapping):
            for k, v in headers.items():
                self[k] = v
        else:
            for k, v in headers:
                self[k] = v

    def copy(self) -> "Headers":
        """
        Return a shallow copy of the headers.
        """
        return Headers(self)

    def __contains__(self, name: object) -> bool:
        """
        Return True if a header name exists in the headers.
        """
        if not isinstance(name, str):
            return False
        n = name.encode(self.encoding).lower()
        return any(key == n for _, key, _ in self._list)

    def __iter__(self) -> typing.Iterator[str]:
        """
        Iterate over header names (decoded).
        """
        seen = set()
        for _, key, _ in self._list:
            sk = key.decode(self.encoding)
            if sk not in seen:
                seen.add(sk)
                yield sk

    def __len__(self) -> int:
        """
        Return the number of distinct header names.
        """
        return len(set(key for _, key, _ in self._list))

    def __eq__(self, other: object) -> bool:
        """
        Equality comparison with another Headers or mapping.
        """
        if isinstance(other, Headers):
            return list(self._list) == list(other._list)
        if isinstance(other, Mapping):
            other_h = Headers(other)
            return list(self._list) == list(other_h._list)
        return False

    def __repr__(self) -> str:
        """
        Representation of the Headers for debugging.
        """
        display = ", ".join(f"{k}: {v}" for k, v in ((rk.decode(self.encoding), val.decode(self.encoding)) for rk, _, val in self._list))
        return f"<Headers [{display}]>"


class Response:
    """
    A minimal HTTP Response object for demonstration.
    """

    def __init__(
        self,
        status_code: int = 200,
        headers: typing.Optional[typing.Union[Headers, Mapping[str, str]]] = None,
        content: typing.Optional[bytes] = None,
        request: typing.Optional[object] = None,
        http_version: str = "HTTP/1.1",
        reason_phrase: typing.Optional[str] = None,
        elapsed: typing.Optional[datetime.timedelta] = None,
        cookies: typing.Optional[CookieJar] = None,
    ) -> None:
        """
        Initialize a Response.

        Provide status_code, optional headers, content bytes, and metadata.
        """
        self.status_code = status_code
        self.headers = Headers(headers) if headers is not None else Headers()
        self._content = content or b""
        self.request = request
        self._http_version = http_version
        self._reason_phrase = reason_phrase or ""
        self._elapsed = elapsed or datetime.timedelta(0)
        self._cookies = cookies or CookieJar()
        self._num_bytes_downloaded = len(self._content)

    def _prepare(self) -> None:
        """
        Internal preparation routine before content access. In a fuller
        implementation this might decode content, set up streaming, etc.
        """
        # This minimal implementation ensures content is bytes.
        if self._content is None:
            self._content = b""

    @property
    def content(self) -> bytes:
        """
        Return the response content as bytes.
        """
        self._prepare()
        return self._content

    @property
    def text(self) -> str:
        """
        Return the response content decoded as text. Uses utf-8 fallback.
        """
        self._prepare()
        # Attempt to detect encoding from headers; fallback to utf-8.
        charset = "utf-8"
        try:
            ctype = self.headers.get_all("content-type")
        except Exception:
            ctype = []
        # Simple parse to find charset
        for part in ctype:
            if "charset=" in part:
                charset = part.split("charset=", 1)[1].strip()
                break
        try:
            return self._content.decode(charset, errors="replace")
        except Exception:
            return self._content.decode("utf-8", errors="replace")

    def json(self) -> typing.Any:
        """
        Parse and return JSON content.
        """
        self._prepare()
        if not self._content:
            return None
        try:
            return jsonlib.loads(self._content.decode("utf-8"))
        except Exception:
            # Try direct bytes parse
            return jsonlib.loads(self._content)

    @property
    def cookies(self) -> CookieJar:
        """
        Return the CookieJar associated with the response.
        """
        return self._cookies

    def num_bytes_downloaded(self) -> int:
        """
        Return the number of bytes that have been downloaded for this response.
        """
        return self._num_bytes_downloaded

    def __repr__(self) -> str:
        """
        Representation including status code and reason.
        """
        return f"<Response [{self.status_code} {self._reason_phrase}]>"

    def __getstate__(self) -> dict:
        """
        Return state for pickling.
        """
        return {
            "status_code": self.status_code,
            "headers": self.headers,
            "content": self._content,
            "http_version": self._http_version,
            "reason_phrase": self._reason_phrase,
            "elapsed": self._elapsed,
        }

    def __setstate__(self, state: dict) -> None:
        """
        Restore state from pickled data.
        """
        self.status_code = state.get("status_code", 0)
        self.headers = state.get("headers", Headers())
        self._content = state.get("content", b"")
        self._http_version = state.get("http_version", "HTTP/1.1")
        self._reason_phrase = state.get("reason_phrase", "")
        self._elapsed = state.get("elapsed", datetime.timedelta(0))
        self._cookies = CookieJar()
        self._num_bytes_downloaded = len(self._content)

    def iter_lines(self, chunk_size: int = 8192) -> typing.Iterator[bytes]:
        """
        Yield the response content as lines split on newline bytes.
        """
        self._prepare()
        if not self._content:
            return
        buf = self._content.splitlines(keepends=True)
        for line in buf:
            yield line

    @property
    def elapsed(self) -> datetime.timedelta:
        """
        Return the elapsed time as a timedelta.
        """
        return self._elapsed

    @property
    def http_version(self) -> str:
        """
        Return the HTTP version used for the response.
        """
        return self._http_version

    @property
    def reason_phrase(self) -> str:
        """
        Return the reason phrase associated with the status code.
        """
        return self._reason_phrase


class QueryParams(typing.MutableMapping[str, str]):
    """
    A minimal query parameters mapping type.
    """

    def __init__(self, params: typing.Optional[typing.Union[str, Mapping[str, str], typing.Iterable[typing.Tuple[str, str]]]] = None) -> None:
        """
        Initialize query parameters from a string, mapping, or iterable.
        """
        self._params: typing.List[typing.Tuple[str, str]] = []
        if params is None:
            return
        if isinstance(params, str):
            for part in params.split("&"):
                if not part:
                    continue
                if "=" in part:
                    k, v = part.split("=", 1)
                else:
                    k, v = part, ""
                self._params.append((k, v))
        elif isinstance(params, Mapping):
            for k, v in params.items():
                self._params.append((k, v))
        else:
            for k, v in params:
                self._params.append((k, v))

    def update(self, params: typing.Union["QueryParams", Mapping[str, str], typing.Iterable[typing.Tuple[str, str]]]) -> None:
        """
        Update parameters with given mapping or iterable of pairs.
        """
        if isinstance(params, QueryParams):
            for k, v in params._params:
                self._params.append((k, v))
        elif isinstance(params, Mapping):
            for k, v in params.items():
                self._params.append((k, v))
        else:
            for k, v in params:
                self._params.append((k, v))

    def __setitem__(self, key: str, value: str) -> None:
        """
        Set a parameter, removing any existing occurrences of the key.
        """
        self._params = [(k, v) for k, v in self._params if k != key]
        self._params.append((key, value))

    def __getitem__(self, key: str) -> str:
        """
        Return the last value for 'key'.
        """
        for k, v in reversed(self._params):
            if k == key:
                return v
        raise KeyError(key)

    def __delitem__(self, key: str) -> None:
        """
        Delete all occurrences of 'key'.
        """
        self._params = [(k, v) for k, v in self._params if k != key]

    def __len__(self) -> int:
        """
        Return the number of parameters (counting duplicates).
        """
        return len(self._params)

    def __iter__(self) -> typing.Iterator[str]:
        """
        Iterate over parameter keys in order.
        """
        for k, _ in self._params:
            yield k

    def __bool__(self) -> bool:
        """
        Truthiness of the QueryParams (True if any params present).
        """
        return bool(self._params)

    def __repr__(self) -> str:
        """
        Representation of query parameters.
        """
        return f"QueryParams({self._params!r})"


class RequestWrapper:
    """
    A tiny wrapper around urllib.request.Request to support add_unredirected_header and info.
    """

    def __init__(self, url: str, headers: typing.Optional[Mapping[str, str]] = None):
        """
        Initialize a RequestWrapper with URL and optional headers.
        """
        self._req = urllib.request.Request(url)
        self._unredirected_headers: dict = {}
        if headers:
            for k, v in headers.items():
                self._req.add_header(k, v)

    def add_unredirected_header(self, name: str, value: str) -> None:
        """
        Add a header that should not be forwarded on redirects.
        """
        self._unredirected_headers[name] = value
        # Also add to underlying request for local use.
        self._req.add_header(name, value)

    def info(self) -> email.message.Message:
        """
        Return headers as an email.message.Message object.
        """
        msg = email.message.Message()
        for k, v in self._req.header_items():
            msg.add_header(k, v)
        # Include unredirected separately if not already included
        for k, v in self._unredirected_headers.items():
            if k not in dict(self._req.header_items()):
                msg.add_header(k, v)
        return msg